+export function countReady(items: Array<{ ready: boolean }>) {
+  // Start the count at zero.
+  let total = 0;
+  // Loop over every item.
+  for (const item of items) {
+    // Check whether the item is ready.
+    if (item.ready) {
+      // Add one to the total.
+      total += 1;
+    }
+  }
+  // Return the total count.
+  return total;
+}
